// Merge MITRE + NVD results with the original alert
// Build a structured threat intel context for the LLM

const alert = $('Filter — True Positives Only').first().json;

// Parse MITRE results safely
let mitreContext = 'No MITRE ATT&CK data returned';
try {
  const mitreRaw = $('MITRE ATT\u0026CK — Search TTPs').first().json;
  const techniques = mitreRaw?.hits?.hits || mitreRaw?.results || [];
  if (techniques.length > 0) {
    mitreContext = techniques.slice(0, 3).map(t => {
      const src = t._source || t;
      return `• ${src.external_id || src.id || 'T????'}: ${src.name || 'Unknown'} — ${(src.description || '').slice(0, 120)}`;
    }).join('\n');
  }
} catch(e) { mitreContext = `MITRE lookup error: ${e.message}`; }

// Parse NVD CVE results safely
let cveContext = 'No CVEs found';
try {
  const nvdRaw = $('NVD — Search CVEs').first().json;
  const cves = nvdRaw?.vulnerabilities || [];
  if (cves.length > 0) {
    cveContext = cves.slice(0, 3).map(v => {
      const cve = v.cve;
      const score = cve?.metrics?.cvssMetricV31?.[0]?.cvssData?.baseScore ||
                    cve?.metrics?.cvssMetricV2?.[0]?.cvssData?.baseScore || 'N/A';
      const desc = cve?.descriptions?.find(d => d.lang === 'en')?.value || '';
      return `• ${cve?.id}: CVSS ${score} — ${desc.slice(0, 100)}`;
    }).join('\n');
  }
} catch(e) { cveContext = `CVE lookup error: ${e.message}`; }

return [{ json: {
  ...alert,
  _mitre_context: mitreContext,
  _cve_context: cveContext
}}];

