parameters.jsCode:
const raw = $input.first().json;
const alert = $('Merge Intel Sources').first().json;

let intel = {};
try {
  const content = raw.choices?.[0]?.message?.content || '{}';
  intel = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  intel = { mitre_ttp_ids: [], mitre_tactic: 'Unknown', related_cves: [], threat_actors: [], detection_gap: 'Parse error', intel_summary: 'Threat intel enrichment failed.' };
}

return [{ json: {
  ...alert,
  _mitre_context: undefined,
  _cve_context: undefined,
  mitre_ttp_ids:        (intel.mitre_ttp_ids || []).join(', '),
  mitre_tactic:         intel.mitre_tactic || '',
  related_cves:         (intel.related_cves || []).join(', '),
  threat_actors:        (intel.threat_actors || []).join(', '),
  detection_gap:        intel.detection_gap || '',
  intel_summary:        intel.intel_summary || '',
  threat_intel_enriched: new Date().toISOString(),
  intel_model:           'qwen/qwen2-7b-instruct:free'
}}];

